import {
  Container,
  Row,
  Col,
  Card,
  Button,
  Badge,
  Pagination,
} from "react-bootstrap";
import { useState, useEffect, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import api from "../services/api";

function HomePage() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeFilter, setActiveFilter] = useState("on_sale");
  const [currentPage, setCurrentPage] = useState(1);
  const navigate = useNavigate();

  const EVENTS_PER_PAGE = 6;

  const getStoredUser = () => {
    try {
      const rawUser = localStorage.getItem("user");
      if (!rawUser || rawUser === "undefined") return null;
      return JSON.parse(rawUser);
    } catch (error) {
      localStorage.removeItem("user");
      return null;
    }
  };

  const user = getStoredUser();

  const getBannerSrc = (bannerImage) => {
    if (!bannerImage) {
      return "https://via.placeholder.com/600x400?text=No+Image";
    }

    if (
      bannerImage.startsWith("http://") ||
      bannerImage.startsWith("https://")
    ) {
      return bannerImage;
    }

    return `/images/${bannerImage}`;
  };

  const getEventCategory = (event) => {
    const now = new Date();
    const eventDate = new Date(event.event_date);
    const status = event.status;

    if (status === "ended" || status === "cancelled" || eventDate < now) {
      return "ended";
    }

    if (status === "on_sale") {
      return "on_sale";
    }

    return "upcoming";
  };

  const getEventCategoryLabel = (category) => {
    switch (category) {
      case "on_sale":
        return "Đang được bán";
      case "upcoming":
        return "Sắp diễn ra";
      case "ended":
        return "Đã kết thúc";
      default:
        return "Không xác định";
    }
  };

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const response = await api.get("/events");

        const eventData = Array.isArray(response.data)
          ? response.data
          : Array.isArray(response.data?.data)
          ? response.data.data
          : [];

        setEvents(eventData);
      } catch (error) {
        console.error("Lỗi khi tải sự kiện:", error);
        setEvents([]);
      } finally {
        setLoading(false);
      }
    };

    fetchEvents();
  }, []);

  const counts = useMemo(() => {
    return {
      on_sale: events.filter((event) => getEventCategory(event) === "on_sale")
        .length,
      upcoming: events.filter((event) => getEventCategory(event) === "upcoming")
        .length,
      ended: events.filter((event) => getEventCategory(event) === "ended")
        .length,
    };
  }, [events]);

  const filteredEvents = useMemo(() => {
    return events.filter((event) => getEventCategory(event) === activeFilter);
  }, [events, activeFilter]);

  const totalPages = Math.ceil(filteredEvents.length / EVENTS_PER_PAGE);

  const paginatedEvents = useMemo(() => {
    const start = (currentPage - 1) * EVENTS_PER_PAGE;
    const end = start + EVENTS_PER_PAGE;
    return filteredEvents.slice(start, end);
  }, [filteredEvents, currentPage]);

  useEffect(() => {
    setCurrentPage(1);
  }, [activeFilter]);

  const renderPagination = () => {
    if (totalPages <= 1) return null;

    const items = [];

    items.push(
      <Pagination.Prev
        key="prev"
        disabled={currentPage === 1}
        onClick={() => setCurrentPage((prev) => prev - 1)}
      />
    );

    for (let page = 1; page <= totalPages; page++) {
      items.push(
        <Pagination.Item
          key={page}
          active={page === currentPage}
          onClick={() => setCurrentPage(page)}
        >
          {page}
        </Pagination.Item>
      );
    }

    items.push(
      <Pagination.Next
        key="next"
        disabled={currentPage === totalPages}
        onClick={() => setCurrentPage((prev) => prev + 1)}
      />
    );

    return (
      <div className="pagination-wrap">
        <Pagination className="pagination-modern">{items}</Pagination>
      </div>
    );
  };

  return (
    <Container className="user-shell home-top-spacing-fix">
      <Row className="mb-5">
        <Col md={12}>
          <Card className="hero-card">
            <Card.Body className="p-4 p-lg-5">
              {user ? (
                <>
                  <div className="mb-3">
                    <span className="hero-chip">🎵 Concert hot</span>
                    <span className="hero-chip">🎫 Vé NFT minh bạch</span>
                    <span className="hero-chip">⚡ Thanh toán nhanh</span>
                  </div>

                  <div className="hero-title">
                    Chào mừng trở lại, {user.full_name}!
                  </div>

                  <div className="hero-text mb-4">
                    Khám phá những sự kiện nổi bật, mua vé nhanh chóng và quản lý
                    vé concert của bạn trên một giao diện hiện đại hơn.
                  </div>

                  <Button
                    className="soft-button soft-button-primary"
                    onClick={() => navigate("/profile")}
                  >
                    Xem hồ sơ & lịch sử mua vé
                  </Button>
                </>
              ) : (
                <>
                  <div className="mb-3">
                    <span className="hero-chip">🎶 Trải nghiệm concert mới</span>
                    <span className="hero-chip">🔐 Blockchain ticket</span>
                  </div>

                  <div className="hero-title">
                    Trải nghiệm mua vé concert hiện đại và minh bạch
                  </div>

                  <div className="hero-text mb-4">
                    Mua vé an toàn, theo dõi đơn hàng, và sở hữu NFT ticket cho các
                    sự kiện âm nhạc lớn nhất.
                  </div>

                  <Button
                    className="soft-button soft-button-primary"
                    onClick={() => navigate("/login")}
                  >
                    Tham gia ngay
                  </Button>
                </>
              )}
            </Card.Body>
          </Card>
        </Col>
      </Row>

      <div className="section-title">Danh sách sự kiện</div>
      <div className="section-subtitle">
        Lọc theo trạng thái để dễ tìm concert phù hợp.
      </div>

      <div className="home-filter-bar">
        <button
          className={`filter-chip ${activeFilter === "on_sale" ? "active" : ""}`}
          onClick={() => setActiveFilter("on_sale")}
        >
          Đang được bán ({counts.on_sale})
        </button>

        <button
          className={`filter-chip ${activeFilter === "upcoming" ? "active" : ""}`}
          onClick={() => setActiveFilter("upcoming")}
        >
          Sắp diễn ra ({counts.upcoming})
        </button>

        <button
          className={`filter-chip ${activeFilter === "ended" ? "active" : ""}`}
          onClick={() => setActiveFilter("ended")}
        >
          Đã kết thúc ({counts.ended})
        </button>
      </div>

      {loading ? (
        <div className="text-center p-5">Đang tải danh sách sự kiện...</div>
      ) : (
        <>
          <Row className="g-4">
            {paginatedEvents.length > 0 ? (
              paginatedEvents.map((event) => {
                const category = getEventCategory(event);

                return (
                  <Col md={6} xl={4} key={event.id}>
                    <Card className="event-card h-100">
                      <div className="event-card-image-wrap">
                        <Card.Img
                          variant="top"
                          src={getBannerSrc(event.banner_image)}
                          alt={event.title}
                          className="event-card-image"
                          onError={(e) => {
                            e.target.src =
                              "https://via.placeholder.com/600x400?text=No+Image";
                          }}
                        />
                      </div>

                      <Card.Body className="p-4 d-flex flex-column">
                        <div className="d-flex justify-content-between align-items-start mb-3">
                          <Badge bg="info" className="event-badge text-dark">
                            Music
                          </Badge>
                          <small className="text-muted fw-semibold">
                            {new Date(event.event_date).toLocaleDateString("vi-VN")}
                          </small>
                        </div>

                        <div className={`event-status-pill ${category} mb-3`}>
                          {getEventCategoryLabel(category)}
                        </div>

                        <div className="event-title">{event.title}</div>

                        <div className="event-meta mb-3">{event.location}</div>

                        <Button
                          className="soft-button soft-button-primary mt-auto"
                          onClick={() => navigate(`/event/${event.id}`)}
                        >
                          Xem chi tiết & đặt vé
                        </Button>
                      </Card.Body>
                    </Card>
                  </Col>
                );
              })
            ) : (
              <Col md={12}>
                <Card className="user-card">
                  <Card.Body className="p-5 text-center text-muted">
                    Không có sự kiện nào trong mục này.
                  </Card.Body>
                </Card>
              </Col>
            )}
          </Row>

          {renderPagination()}
        </>
      )}
    </Container>
  );
}

export default HomePage;
